-- ==========================================
-- FREQUENTLY ASKED QUESTIONS
-- ==========================================
P.FAQ = {
    {
        q = "How do I move UI elements? (e.g.Player Frame, Party Frame, Cast Bar, etc...)",
        a = "OakUI heavily relies on QUI's Anchoring system and this is why elements say LOCKED in edit mode. To move them, go to QUI's Anchoring & Layout tab and you can either disable the override, or, you can adjust their position with the x/y adjustment bars.",
        quiTab = "Anchoring & Layout" 
    },
	{
        q = "How do I resize or move my Action Bars?",
        a = "Action bars are controlled by Blizzard's Edit Mode. You can change their layout there. To move them, you will need to disable the override in QUI's Anchoring & Layout tab.",
        quiTab = "Anchoring & Layout" 
    },
    {
        q = "How do I change the size of my Party or Raid frames?",
        a = "If you are using the primary OAK UI setup, your group frames are handled by QUI. Open the options, navigate to the Group Frames section, and you can adjust the width, height, and display conditions.",
        quiTab = "Group Frames"
    },
	{
        q = "Why do I see multiple party frames?",
        a = "OakUI has moved away from using the Danders Frames addon and instead uses QUI's built in Party & Raid Frames. If you see multiple party frames, you will need to disable Danders Frames, OR, Alternatively disable QUI's party/raid frames.", 
		quiTab = "Group Frames"
    },
	{
        q = "How do I adjust the font size of the objective/quest tracker?",
        a = "Skinning & Autohide, Skinning, Objective Tracker  Objective Text font & Module Header Font.", 
		quiTab = "Skinning & Autohide"
    },
    {
        q = "My UI looks like a mess and everything is overlapping. What did I miss?",
        a = "You likely missed STEP 1 of the installation! You must click 'Copy Layout' on the Blizzard Edit Mode row, open WoW's Edit Mode (Esc -> Edit Mode), click Import, and paste the string to position the base frames correctly."
    },
    {
        q = "How do I get the custom font to show up on the 3D names floating above players?",
        a = "Due to WoW engine limitations, addons cannot change 3D world text automatically. You must install the font manually. Go to the 'Custom Fonts' tab in this installer and follow the 4 simple steps."
    },
    {
        q = "Why are my chat windows missing tabs or positioned weirdly?",
        a = "Simply click the 'Apply Layout' button next to the OakUI Chat Layout row in the installer. This will instantly snap your chat windows back into the intended OAK format with the correct General and Loot tabs."
    }
}

